const fs = require('fs');
const path = require('path');

const jobDir = $env.NVF_JOB_DIR || '/media/scripts';
const pendingStatuses = ['draft', 'needs-review'];

let files = [];
try {
  files = fs.readdirSync(jobDir).filter((name) => name.endsWith('.json'));
} catch (error) {
  return [{ json: { ok: true, count: 0, pending: [], note: `Job directory not found yet: ${jobDir}` } }];
}

const pending = [];
for (const fileName of files) {
  const filePath = path.join(jobDir, fileName);
  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    const job = JSON.parse(raw);
    if (pendingStatuses.includes(job.status)) {
      pending.push({
        jobId: job.jobId,
        project: job.project,
        pillar: job.pillar,
        idea: job.idea,
        targetAudience: job.targetAudience,
        cta: job.cta,
        status: job.status,
        createdAt: job.createdAt
      });
    }
  } catch (error) {
    // Skip unreadable/malformed job files instead of failing the whole listing.
    continue;
  }
}

pending.sort((a, b) => String(a.createdAt).localeCompare(String(b.createdAt)));

return [{ json: { ok: true, count: pending.length, pending } }];

const fs = require('fs');
const path = require('path');

const body = $input.first().json.body || {};
const jobDir = $env.NVF_JOB_DIR || '/media/scripts';

const jobId = String(body.jobId || '').trim();
const decision = String(body.decision || '').trim();
const reviewer = body.reviewer || null;
const notes = body.notes || null;

const allowedDecisions = ['approved', 'rejected'];

if (!jobId) {
  throw new Error('jobId is required');
}
if (!allowedDecisions.includes(decision)) {
  throw new Error(`decision must be one of: ${allowedDecisions.join(', ')}`);
}

const filePath = path.join(jobDir, `${jobId}.json`);
if (!fs.existsSync(filePath)) {
  throw new Error(`Job not found: ${jobId}`);
}

const job = JSON.parse(fs.readFileSync(filePath, 'utf8'));
const reviewedAt = new Date().toISOString();

job.status = decision;
job.updatedAt = reviewedAt;
job.review = {
  decision,
  reviewer,
  reviewedAt,
  notes
};

// Safety rules are never overridable by the review payload.
job.requiresHumanReview = true;
job.autoPublish = false;

fs.writeFileSync(filePath, JSON.stringify(job, null, 2), 'utf8');

return [{ json: { ok: true, jobId, status: job.status, review: job.review, job } }];
